                            DurationFieldType rangeType = fieldType.getRangeDurationType();
                            DurationFieldType loopRangeType = loopType.getRangeDurationType();
                            if (rangeType == null) {
                                // new field is larger in range than any with non-null range
                                if (loopRangeType != null) {
                                    break;
                                }
                            } else if (loopRangeType == null) {
                                // new field is smaller than loop field with null range; continue
                            } else {
                                DurationField rangeField = rangeType.getField(iChronology);
                                DurationField loopRangeField = loopRangeType.getField(iChronology);
